#include <float.h>
#include <math.h>
#include <stdbool.h>

/*
 * Computes a medication dosage in mg/kg.
 *
 * dosage_out = weight_kg * factor
 *
 * Safety / validation:
 * - weight_kg must be finite and > 0.0
 * - factor must be finite and >= 0.0
 * - The product must be representable as a finite double
 * - No undefined behavior (no invalid pointer dereference, no NaN
 *   produced intentionally, no overflow in floating-point arithmetic)
 *
 * Returns:
 * - true  on success (dosage_out is set)
 * - false on any validation failure (dosage_out is set to 0.0)
 */
bool compute_dosage_mg_per_kg(double weight_kg,
                              double factor,
                              double *dosage_out)
{
    double abs_weight;
    double abs_factor;

    if (dosage_out == (double *)0) {
        /* Invalid output pointer */
        return false;
    }

    /* Initialize output to a safe value on all paths */
    *dosage_out = 0.0;

    /* Check that inputs are finite (not NaN, not +/-Inf) */
    if (!isfinite(weight_kg)) {
        return false;
    }
    if (!isfinite(factor)) {
        return false;
    }

    /* Domain checks for this particular calculation */
    if (weight_kg <= 0.0) {
        /* Non-positive weight is invalid in this context */
        return false;
    }
    if (factor < 0.0) {
        /* Negative factor would imply a negative dosage */
        return false;
    }

    /*
     * Prevent overflow before performing the multiplication.
     * For finite doubles a and b, overflow can only occur if
     * |a| > DBL_MAX / |b| (and b != 0).
     */
    abs_weight = fabs(weight_kg);
    abs_factor = fabs(factor);

    if (abs_factor > 0.0) {
        if (abs_weight > (DBL_MAX / abs_factor)) {
            /* The result would overflow to Inf */
            return false;
        }
    }

    /*
     * At this point multiplication cannot overflow and both operands
     * are finite and non-negative. The result will be finite.
     */
    *dosage_out = weight_kg * factor;

    /*
     * As a defensive check, verify the result is finite.
     * This should always be true given the checks above.
     */
    if (!isfinite(*dosage_out)) {
        *dosage_out = 0.0;
        return false;
    }

    return true;
}
